Below is a simple implementation of a Genetic Algorithm (GA) in C++ that evolves a population of binary strings to find an optimal solution to a specific problem. In this case, the problem is to find a binary string that matches a target string of 1010101010. The GA will generate a population of binary strings, evaluate their fitness based on how close they are to the target, perform selection, crossover, and mutation, and continue evolving the population until a solution is found or a maximum number of generations is reached.

```cpp
#include <iostream>
#include <vector>
#include <string>
#include <random>
#include <algorithm>

using namespace std;

// Function to generate a random binary string of a given length
string generateRandomString(int length) {
    string str(length, '0');
    random_device rd;
    mt19937 gen(rd());
    uniform_int_distribution<> dis(0, 1);
    for (int i = 0; i < length; ++i) {
        str[i] = dis(gen) ? '1' : '0';
    }
    return str;
}

// Function to calculate the fitness of a binary string
int calculateFitness(const string& individual, const string& target) {
    int fitness = 0;
    for (size_t i = 0; i < individual.length(); ++i) {
        if (individual[i] == target[i]) {
            fitness++;
        }
    }
    return fitness;
}

// Function to perform crossover between two parents
string crossover(const string& parent1, const string& parent2) {
    int crossoverPoint = rand() % parent1.length();
    string child(parent1.length(), '0');
    for (int i = 0; i < parent1.length(); ++i) {
        if (i < crossoverPoint) {
            child[i] = parent1[i];
        } else {
            child[i] = parent2[i];
        }
    }
    return child;
}

// Function to perform mutation on a string
string mutate(string individual) {
    random_device rd;
    mt19937 gen(rd());
    uniform_int_distribution<> dis(0, individual.length() - 1);
    int mutationPoint = dis(gen);
    if (individual[mutationPoint] == '0') {
        individual[mutationPoint] = '1';
    } else {
        individual[mutationPoint] = '0';
    }
    return individual;
}
